### Step 3: Logging in CRUD Operations and Services

You can also use the logger in your CRUD operations and services to log important events.

#### `crud.py`
```python
from sqlalchemy.orm import Session
from app.models import User, Task
from app.schemas import TaskCreate, Task
from app.logging_config import logger

def get_tasks(db: Session, skip: int = 0, limit: int = 100, user: User = None):
    if user:
        logger.info(f"Fetching tasks for user {user.email} with skip={skip} and limit={limit}")
        return db.query(Task).filter(Task.user_id == user.id).offset(skip).limit(limit).all()
    else:
        logger.info(f"Fetching all tasks with skip={skip} and limit={limit}")
        return db.query(Task).offset(skip).limit(limit).all()

def get_task(db: Session, task_id: int, user: User = None):
    if user:
        logger.info(f"Fetching task {task_id} for user {user.email}")
        return db.query(Task).filter(Task.user_id == user.id, Task.id == task_id).first()
    else:
        logger.info(f"Fetching task {task_id}")
        return db.query(Task).filter(Task.id == task_id).first()

def create_task(db: Session, task: TaskCreate, user: User):
    logger.info(f"Creating task for user {user.email} with title={task.title} and description={task.description}")
    db_task = Task(**task.dict(), user_id=user.id)
